152: function deriveKey() {
153:   try {
154:     const { machineIdSync } = require("node-machine-id");
155:     const raw = machineIdSync();
156:     return crypto.createHash("sha256").update(raw + ENCRYPT_SALT).digest();
157:   } catch {
158:     return crypto.createHash("sha256").update(ENCRYPT_SALT).digest();
159:   }
160: }
