162: function encryptPassword(plaintext) {
163:   const key = deriveKey();
164:   const iv = crypto.randomBytes(12);
165:   const cipher = crypto.createCipheriv(ENCRYPT_ALGO, key, iv);
166:   const encrypted = Buffer.concat([cipher.update(plaintext, "utf8"), cipher.final()]);
167:   const tag = cipher.getAuthTag();
168:   return `${iv.toString("hex")}:${tag.toString("hex")}:${encrypted.toString("hex")}`;
169: }
