171: function decryptPassword(stored) {
172:   try {
173:     const [ivHex, tagHex, dataHex] = stored.split(":");
174:     if (!ivHex || !tagHex || !dataHex) return null;
175:     const key = deriveKey();
176:     const decipher = crypto.createDecipheriv(ENCRYPT_ALGO, key, Buffer.from(ivHex, "hex"));
177:     decipher.setAuthTag(Buffer.from(tagHex, "hex"));
178:     return decipher.update(Buffer.from(dataHex, "hex")) + decipher.final("utf8");
179:   } catch {
180:     return null;
181:   }
182: }
