411:   const attempt = mitmRestartCount;
412:   const delay = MITM_RESTART_DELAYS_MS[Math.min(attempt, MITM_RESTART_DELAYS_MS.length - 1)];
413:   mitmRestartCount++;
414:   mitmIsRestarting = true;
415: 
416:   log(`Restarting in ${delay / 1000}s... (${mitmRestartCount}/${MITM_MAX_RESTARTS})`);
417:   await new Promise((r) => setTimeout(r, delay));
