469:       if (fs.existsSync(PID_FILE)) {
470:         const savedPid = parseInt(fs.readFileSync(PID_FILE, "utf-8").trim(), 10);
471:         if (savedPid && isProcessAlive(savedPid)) {
472:           serverPid = savedPid;
473:           log(`♻️ Reusing existing process (PID: ${savedPid})`);
474:           await saveMitmSettings(true, sudoPassword);
475:           if (sudoPassword) setCachedPassword(sudoPassword);
476:           return { running: true, pid: savedPid };
477:         } else {
478:           fs.unlinkSync(PID_FILE);
479:         }
480:       }
481:     } catch { /* ignore */ }
482:   }
