499:           log(`Killing process on port 443 (PID ${owner.pid}, name=${shortName})...`);
500:           await killPort443Owner(owner, sudoPassword);
501:         } else {
502:           const e = new Error(`Port 443 is already in use by "${shortName}" (PID ${owner.pid}).`);
503:           e.code = "PORT_443_BUSY";
504:           e.portOwner = { pid: owner.pid, name: shortName };
505:           throw e;
506:         }
507:       }
508:     }
509:   }
