511:   // Step 1: Generate Root CA if missing or expired
512:   const rootCACertPath = path.join(MITM_DIR, "rootCA.crt");
513:   const rootCAKeyPath = path.join(MITM_DIR, "rootCA.key");
514:   const certExists = fs.existsSync(rootCACertPath) && fs.existsSync(rootCAKeyPath);
515: 
516:   if (!certExists || isCertExpired(rootCACertPath)) {
517:     if (certExists) {
518:       // Uninstall expired cert from system store before regenerating
519:       log("🔐 Cert expired — uninstalling old cert...");
520:       const password = sudoPassword || getCachedPassword() || await loadEncryptedPassword();
521:       try { await uninstallCert(password, rootCACertPath); } catch { /* best effort */ }
522:     }
523:     log("🔐 Generating Root CA...");
524:     await generateCert();
