526: 
527:   // Step 1.5: Auto-install Root CA if not trusted yet
528:   const { checkCertInstalled } = require("./cert/install");
529:   const rootCATrusted = await checkCertInstalled(rootCACertPath);
530:   const linuxNoSystemTrust = !IS_WIN && !IS_MAC && !isSudoAvailable();
531:   if (!rootCATrusted) {
532:     log("🔐 Cert: not trusted → installing...");
533:     const password = sudoPassword || getCachedPassword() || await loadEncryptedPassword();
534:     if (linuxNoSystemTrust) {
535:       log(`🔐 Cert: skipping system trust (no sudo). Install ${rootCACertPath} as a trusted CA on machines that use this proxy.`);
536:     } else {
537:       if (!password && isSudoPasswordRequired()) {
538:         throw new Error("Sudo password required to install Root CA certificate");
539:       }
540:       try {
541:         await installCert(password, rootCACertPath);
542:         log("🔐 Cert: ✅ trusted");
543:       } catch (e) {
544:         throw new Error(`Failed to trust certificate: ${e.message}`);
545:       }
546:     }
547:   } else {
548:     log("🔐 Cert: already trusted ✅");
