551:   // Step 2: Spawn server (Root CA already installed in Step 1.5)
552:   // Verify server.js exists — recopy if runtime file was deleted (antivirus/cleanup)
553:   let effectiveServerPath = SERVER_PATH;
554:   if (!effectiveServerPath || !fs.existsSync(effectiveServerPath)) {
555:     log(`[MITM] server.js missing at ${effectiveServerPath} → recopying`);
556:     effectiveServerPath = ensureRuntimeServer(resolveBundledServerPath());
557:     if (!effectiveServerPath || !fs.existsSync(effectiveServerPath)) {
558:       throw new Error(`MITM server.js not found at ${effectiveServerPath}. Reinstall Audira Route.`);
